mapper.select:
SELECT T.ID, T.DEVICE_IP, T.CREATE_USER, T.CREATE_TIME, NULL AS DEVICE_AREA, DN.NODE_NAME AS DEVICE_HOME, T.DEVICE_SSH_PWD, T.DEVICE_SSH_USR, T.ENABLE_STATUS, T.CONN_STATUS, T.REMARK, T.UPDATE_TIME, T.NODE_ID, T.PORT, T.ARCH_TYPE, T.CPU_CORE, T.MEM_TOTAL, T.DISK_TOTAL, T.OS_NAME, T.OS_VERSION, T.CPU_DESC FROM T_DEVICE T INNER JOIN T_DEVICE_NODE DN ON T.NODE_ID=DN.ID
AND T.NODE_ID IN
#{id}
AND DN.NODE_NAME like concat('%', #{params.deviceHome}, '%')
AND T.CONN_STATUS = #{params.connStatus}
AND T.DEVICE_IP like concat('%', #{params.deviceIp}, '%')
AND T.CREATE_TIME BETWEEN #{beginTime} AND #{endTime}
ORDER BY T.CREATE_TIME DESC

SELECT T_DEVICE_NODE.ID DEVICE_HOME_ID,T_DEVICE.DEVICE_IP FROM T_DEVICE,T_DEVICE_NODE WHERE T_DEVICE.NODE_ID=T_DEVICE_NODE.ID AND ENABLE_STATUS='0'
AND DEVICE_IP IN
#{deviceIp}
